    if (payload == null || payload.trim().isEmpty) return const [];

    try {
      final decodedArr = (jsonDecode(payload) as List).cast<Map>();
      return decodedArr
          .map((m) => FractalPalette.fromJson(m.cast<String, Object?>()))
          .where((p) => p.id.isNotEmpty)
